#include <iostream>
#include <cstring>
#include <algorithm>
using namespace std;
int sum[505], a1[505], b1[505];
int main()
{
    string a,b;
    cin>>a>>b;
    reverse(a.begin(),a.end());
    reverse(b.begin(),b.end());
    for(int i=0;i<=a.size()-1;i++)
    {
        a1[i]=a[i]-48;
    }
    for(int i=0;i<=b.size()-1;i++)
    {
        b1[i]=b[i]-48;
    }
    int len=max(a.size(),b.size());
    for(int i=0;i<=len-1;i++)
    {
        sum[i]=a1[i]+b1[i]+sum[i];
        sum[i+1]=sum[i]/10;
        sum[i]=sum[i]%10;
    }
    while(sum[len]==0&&len>0)
    {
        len--;
    }
    for(int i=len;i>=0;i--)
    {
        cout<<sum[i];
    }
    return 0;
}
